import json

# Load all metadata for 2015
metadata_file = locals()['var_functions.query_db:0']
with open(metadata_file, 'r') as f:
    metadata_2015 = json.load(f)

# Create mapping of article_id to region
article_id_to_region = {}
for item in metadata_2015:
    article_id_to_region[int(item['article_id'])] = item['region']

# Get all article IDs
all_article_ids = list(article_id_to_region.keys())

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(all_article_ids),
    'region_sample': {k: article_id_to_region[k] for k in list(article_id_to_region)[:5]}
}))

