args.code:
import json

# Load metadata file and create mapping
metadata_file = locals()['var_functions.query_db:0']
with open(metadata_file, 'r') as f:
    metadata_2015 = json.load(f)

article_id_to_region = {}
for item in metadata_2015:
    article_id_to_region[int(item['article_id'])] = item['region']

# Get first 50 article IDs for testing
article_ids = list(article_id_to_region.keys())
test_batch = article_ids[:50]

# Create MongoDB query filter
query_filter = {
    "article_id": {"$in": [str(id) for id in test_batch]}
}

print('__RESULT__:')
print(json.dumps({
    'query_filter': str(query_filter),
    'batch_size': len(test_batch),
    'first_five_ids': test_batch[:5]
}))

